// === RUN PREDATORY SCAN (D.6 Phase 2) ===
// Appelle l'endpoint Flask /api/predatory-check qui fait le scoring via predatory_check.py
// Timeout 30 min car les APIs DOAJ/MEDLINE/Crossref peuvent etre lentes sur gros volumes.
const articles = $input.all().map(i => i.json);
const FLASK = 'http://host.docker.internal:8080';

console.log('[PredatoryScan] Envoi ' + articles.length + ' articles a /api/predatory-check');

const resp = await this.helpers.httpRequest({
  method: 'POST',
  url: FLASK + '/api/predatory-check',
  body: JSON.stringify({ articles: articles, do_external_apis: true }),
  headers: { 'Content-Type': 'application/json' },
  timeout: 1800000,  // 30 min
  json: true,
});

if (!resp || !resp.success) {
  const errMsg = (resp && resp.error) || 'Reponse Flask invalide';
  console.log('[PredatoryScan] Erreur : ' + errMsg);
  // On retourne quand meme les articles non-scores pour ne pas tout perdre
  return articles.map(a => ({ json: { ...a, _predatory_error: errMsg, _predatory_score: null, _predatory_level: 'unknown', _predatory_flag: 'gray', _predatory_reasons: [] } }));
}

const scanned = resp.scanned || [];
const summary = resp.summary || {};
console.log('[PredatoryScan] OK : ' + scanned.length + ' articles scannes');
console.log('[PredatoryScan] Repartition : ' + JSON.stringify(summary.by_level || {}));

return scanned.map(a => ({ json: a }));
